parameters.jsCode:
const tasks = $input.all();
const now = new Date();

// Calculate workload per assignee
const workloadMap = {};
tasks.forEach(task => {
  if (task.json.assignee) {
    const assigneeId = task.json.assignee.gid;
    const assigneeName = task.json.assignee.name || 'Unnamed';
    if (!workloadMap[assigneeId]) {
      workloadMap[assigneeId] = { name: assigneeName, count: 0, tasks: [] };
    }
    workloadMap[assigneeId].count++;
    workloadMap[assigneeId].tasks.push(task.json.name);
  }
});

// Format tasks for AI analysis
const formattedTasks = tasks.map(task => {
  const dueDate = task.json.due_on || task.json.due_at;
  let daysUntilDue = null;

  if (dueDate) {
    const due = new Date(dueDate);
    daysUntilDue = Math.ceil((due - now) / (1000 * 60 * 60 * 24));
  }

  const assigneeId = task.json.assignee?.gid;
  const assigneeWorkload = assigneeId ? workloadMap[assigneeId].count : 0;

  return {
    task_id: task.json.gid,
    task_name: task.json.name,
    description: task.json.notes || '',
    due_date: dueDate,
    days_until_due: daysUntilDue,
    assignee: task.json.assignee?.name || 'Unassigned',
    assignee_workload: assigneeWorkload,
    num_dependencies: (task.json.dependencies || []).length,
    num_dependents: (task.json.dependents || []).length,
    num_subtasks: task.json.num_subtasks || 0,
    tags: (task.json.tags || []).map(t => t.name).join(', '),
    created_at: task.json.created_at
  };
});

// Create context summary
const contextSummary = {
  total_tasks: tasks.length,
  team_workload: Object.values(workloadMap).map(w => ({
    name: w.name,
    active_tasks: w.count
  })),
  tasks: formattedTasks
};

return [{ json: contextSummary }];

parameters.text:
=Analyze the following tasks and assign priority scores (1-100) and priority levels (Critical/High/Medium/Low) based on deadlines, dependencies, and team workload.

Context:
Total Tasks: {{ $json.total_tasks }}

Team Workload:
{{ $json.team_workload.map(w => `- ${w.name}: ${w.active_tasks} active tasks`).join('\n') }}

Tasks to prioritize:
{{ $json.tasks.map((t, i) => `
${i+1}. ${t.task_name}
   - ID: ${t.task_id}
   - Due: ${t.days_until_due !== null ? (t.days_until_due >= 0 ? `in ${t.days_until_due} days` : `OVERDUE by ${Math.abs(t.days_until_due)} days`) : 'No due date'}
   - Assignee: ${t.assignee} (${t.assignee_workload} tasks)
   - Dependencies: ${t.num_dependencies} blocking, ${t.num_dependents} blocked by
   - Subtasks: ${t.num_subtasks}
   - Tags: ${t.tags || 'None'}`).join('\n') }}

Analyze each task and provide priority scores with reasoning.
